Infer({method:'MCMC', burn:10000, samples: 50000, onlyMAP:false}, function() {
  var vocab = ['dogs', 'cats', 'chase', 'sleep', 'stop'];

  var wordToDistribution = mem(function(word) {
    return dirichletDrift({alpha: ones([vocab.length, 1]), concentration: 10});
  });

  var transition = function(word) {
    return categorical({ps: wordToDistribution(word), vs: vocab});
  };

  // Recursive generator: from a starting word, sample transitions until 'stop'
  var generateSentence = function(word) {
    var next = transition(word);
    if (next === 'stop') {
      return [word];
    } else {
      return [word].concat(generateSentence(next));
    }
  };

  // Recursive conditioning: observe each consecutive bigram in a word list,
  // and observe that the last word is followed by 'stop'
  var conditionOnSentence = function(words) {
    if (words.length === 1) {
      // Last word must be followed by 'stop'
      observe(Categorical({ps: wordToDistribution(words[0]), vs: vocab}), 'stop');
    } else {
      // Current word is followed by next word
      observe(Categorical({ps: wordToDistribution(words[0]), vs: vocab}), words[1]);
      conditionOnSentence(words.slice(1));
    }
  };

  // Condition on having observed 'dogs chase cats'
  conditionOnSentence(['dogs', 'chase', 'cats']);

  // Return the posterior over what word follows 'chase'
  return transition('chase');
})

